mapper.select:
SELECT a.id AS id, a.address AS address, a.addressCode, a.areaCode, a.channelId, a.channelName, a.channelCode, a.remark, a.status, a.operatorTime, a.operator, a.chooseFlag, a.channelTotal from ( select
t.id AS id, t.address AS address, t.address_code AS addressCode, t.area_code AS areaCode, t.channel_id AS channelId, t.channel_name AS channelName, t.channel_code AS channelCode, t.remark AS remark, t.status AS status,
CASE WHEN t1.created_time IS NOT NULL THEN t1.created_time ELSE t.updated_time END AS operatorTime,
CASE WHEN t1.creator IS NOT NULL THEN t1.creator ELSE t.creator END AS operator,
CASE WHEN t.channel_code = t1.channel_code THEN 1 ELSE 0 END AS chooseFlag,
(SELECT COUNT(1) FROM sms_channel_config scc WHERE scc.channel_code = t1.channel_code) AS channelTotal
FROM sms_channel_config t LEFT JOIN sms_site_link t1 ON t.channel_code = t1.channel_code AND t1.site_code = #{vo.siteCode}
AND t.address_code = #{vo.addressCode}
AND t.channel_name = #{vo.channelName}
AND t.channel_code = #{vo.channelCode}
) a
ORDER BY a.channelTotal desc ,a.status DESC, a.operatorTime DESC
